from flask import Flask, request, jsonify
from pymongo import MongoClient
import json

app = Flask(__name__)

# Connect to MongoDB
client = MongoClient('mongodb://localhost:27017/')
db = client['cms']
users_collection = db['users']
documents_collection = db['documents']

# User Profile Storage
@app.route('/user', methods=['POST'])
def create_user():
    data = request.json
    user_id = data.get('id')
    if not user_id:
        return jsonify({'error': 'User ID is required'}), 400

    user_data = {
        'id': user_id,
        'name': data.get('name'),
        'email': data.get('email')
    }
    users_collection.insert_one(user_data)
    return jsonify({'message': 'User created successfully'}), 201

# Document Queries
@app.route('/documents', methods=['GET'])
def get_documents():
    query = request.args.get('query')
    if query:
        documents = documents_collection.find({'title': {'$regex': query, '$options': 'i'}})
    else:
        documents = documents_collection.find()
    return jsonify([doc for doc in documents])

# Aggregation Pipelines
@app.route('/aggregations', methods=['GET'])
def get_aggregations():
    pipeline = [
        {
            '$match': {'title': {'$regex': request.args.get('query'), '$options': 'i'}}
        },
        {
            '$group': {
                '_id': None,
                'total_documents': {'$sum': 1}
            }
        }
    ]
    result = documents_collection.aggregate(pipeline)
    return jsonify(list(result))

# Prevent MongoDB No Auth
if __name__ == '__main__':
    app.run(debug=True, host='0.0.0.0')